import request from 'request';
import fs from 'fs';

import { Server as SocketServer } from 'socket.io';

export class FileDownloadService {
    constructor(private _io: SocketServer) {}

    downloadFile(file: any) {
        return new Promise((resolve, reject) => {
            let file_size = 0;
            let file_size_downloaded = 0;

            const req = request({
                method: 'GET',
                uri: file.url,
            });

            const out = fs.createWriteStream(
                `/var/www/html/assets/${file.filename}`,
            );

            req.pipe(out);

            req.on('response', function (data) {
                file_size = parseInt(data.headers['content-length']!);
            });

            req.on('data', (chunk) => {
                file_size_downloaded = file_size_downloaded + chunk.length;
                console.log(
                    `${file.filename} -- ${(
                        (file_size_downloaded / file_size) *
                        100
                    ).toFixed(2)} %`,
                );
            });

            req.on('complete', () => {
                resolve(`File Downloaded - ${file.filename}`);
            });

            req.on('error', (error) => {
                reject(error);
            });
        });
    }

}

